import React, { useState } from 'react';
import CommunityArticleCard from '../components/CommunityArticleCard';
import CreateStoryModal from '../components/CreateStoryModal';
import Button from '../components/Button';

const NewsstandPage = () => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [articles, setArticles] = useState([
        {
            id: 101,
            title: "Local Coffee Shop Goes Zero Waste",
            category: "Local",
            imageUrl: "https://images.unsplash.com/photo-1509042239860-f550ce710b93?auto=format&fit=crop&q=80&w=800",
            author: "Alex Rivera",
            authorAvatar: "https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?auto=format&fit=crop&q=80&w=200",
            efficacy: 98,
            upvotes: 342
        },
        {
            id: 102,
            title: "Review: The New Downtown Park",
            category: "Review",
            imageUrl: "https://images.unsplash.com/photo-1519331379826-f9478558d136?auto=format&fit=crop&q=80&w=800",
            author: "Sarah Chen",
            authorAvatar: "https://images.unsplash.com/photo-1438761681033-6461ffad8d80?auto=format&fit=crop&q=80&w=200",
            efficacy: 85,
            upvotes: 128
        },
        {
            id: 103,
            title: "Why I'm Switching to E-Bikes",
            category: "Opinion",
            imageUrl: "https://images.unsplash.com/photo-1571068316344-75bc76f77890?auto=format&fit=crop&q=80&w=800",
            author: "Mike Johnson",
            authorAvatar: "https://images.unsplash.com/photo-1500648767791-00dcc994a43e?auto=format&fit=crop&q=80&w=200",
            efficacy: 92,
            upvotes: 215
        }
    ]);

    const handleCreateStory = (newStory) => {
        const story = {
            id: Date.now(),
            ...newStory,
            author: "You", // Mock current user
            authorAvatar: "https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?auto=format&fit=crop&q=80&w=200",
            efficacy: 100, // New authors start high? Or 0? Let's say 100 for encouragement
            upvotes: 0
        };
        setArticles([story, ...articles]);
    };

    return (
        <div className="min-h-screen bg-cream-50 px-6 py-12">
            <div className="max-w-7xl mx-auto">
                {/* Header */}
                <div className="flex flex-col md:flex-row justify-between items-end mb-16 border-b-4 border-black pb-8">
                    <div>
                        <h1 className="font-serif text-6xl md:text-7xl font-black mb-4">THE NEWSSTAND</h1>
                        <p className="text-xl font-bold text-gray-500">Community-driven journalism. Validated by you.</p>
                    </div>
                    <div className="mt-6 md:mt-0">
                        <Button onClick={() => setIsModalOpen(true)} variant="primary" className="text-lg">
                            ✎ START REPORTING
                        </Button>
                    </div>
                </div>

                {/* Community Feed */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {articles.map((article) => (
                        <CommunityArticleCard
                            key={article.id}
                            {...article}
                            initialUpvotes={article.upvotes}
                        />
                    ))}
                </div>

                {/* Empty State / Call to Action */}
                {articles.length === 0 && (
                    <div className="text-center py-20">
                        <p className="text-2xl font-bold text-gray-400 mb-4">Be the first to break the news.</p>
                        <Button onClick={() => setIsModalOpen(true)} variant="outline">WRITE A STORY</Button>
                    </div>
                )}
            </div>

            <CreateStoryModal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                onSubmit={handleCreateStory}
            />
        </div>
    );
};

export default NewsstandPage;
